/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn first(
    &self,
    /// If given, the first grapheme cluster matching this character
    /// class is returned instead of the very first one.
    #[named]
    pattern: Option<CharClass>,
    /// If given, the returned grapheme cluster is converted to the
    /// specified case.
    #[named]
    case: Option<LetterCase>,
) -> StrResult<Str> {
    if self.0.is_empty() {
        return Err(string_is_empty());
    }
    let grapheme = match pattern {
        None => self.0.graphemes(true).next().unwrap(),
        Some(pattern) => self
            .0
            .graphemes(true)
            .find(|g| g.chars().next().is_some_and(|c| pattern.matches(c)))
            .ok_or_else(|| no_grapheme_matching_pattern(pattern))?,
    };
    Ok(match case {
        Some(case) => case.apply(grapheme),
        None => grapheme.into(),
    })
}

/// Extracts the last grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn last(
    &self,
    /// If given, the last grapheme cluster matching this character
    /// class is returned instead of the very last one.
    #[named]
    pattern: Option<CharClass>,
    /// If given, the returned grapheme cluster is converted to the
    /// specified case.
    #[named]
    case: Option<LetterCase>,
) -> StrResult<Str> {
    if self.0.is_empty() {
        return Err(string_is_empty());
    }
    let grapheme = match pattern {
        None => self.0.graphemes(true).next_back().unwrap(),
        Some(pattern) => self
            .0
            .graphemes(true)
            .rfind(|g| g.chars().next().is_some_and(|c| pattern.matches(c)))
            .ok_or_else(|| no_grapheme_matching_pattern(pattern))?,
    };
    Ok(match case {
        Some(case) => case.apply(grapheme),
        None => grapheme.into(),
    })
}

