/// A character class that can be matched against by
/// [`str.first`]($str.first) and [`str.last`]($str.last).
#[derive(Debug, Copy, Clone, Eq, PartialEq, Hash, Cast)]
pub enum CharClass {
    /// An alphabetic grapheme.
    Alpha,
    /// A numeric grapheme.
    Numeric,
    /// An alphabetic or numeric grapheme.
    Alphanumeric,
    /// An uppercase grapheme.
    Uppercase,
    /// A lowercase grapheme.
    Lowercase,
    /// A whitespace grapheme.
    Whitespace,
}

impl CharClass {
    /// Whether the given character belongs to this class.
    fn matches(self, c: char) -> bool {
        match self {
            Self::Alpha => c.is_alphabetic(),
            Self::Numeric => c.is_numeric(),
            Self::Alphanumeric => c.is_alphanumeric(),
            Self::Uppercase => c.is_uppercase(),
            Self::Lowercase => c.is_lowercase(),
            Self::Whitespace => c.is_whitespace(),
        }
    }
}

/// A letter case that [`str.first`]($str.first) and [`str.last`]($str.last)
/// can convert their result to.
#[derive(Debug, Copy, Clone, Eq, PartialEq, Hash, Cast)]
pub enum LetterCase {
    /// Converts to uppercase.
    Upper,
    /// Converts to lowercase.
    Lower,
    /// Uppercases the first scalar value and lowercases the rest.
    Title,
}

impl LetterCase {
    /// Apply the case to a grapheme cluster.
    fn apply(self, grapheme: &str) -> Str {
        match self {
            Self::Upper => grapheme.to_uppercase().into(),
            Self::Lower => grapheme.to_lowercase().into(),
            Self::Title => {
                let mut chars = grapheme.chars();
                match chars.next() {
                    Some(first) => {
                        let mut out: EcoString = first.to_uppercase().collect();
                        out.push_str(chars.as_str().to_lowercase().as_str());
                        out.into()
                    }
                    None => Str::new(),
                }
            }
        }
    }
}

/// The error message when no grapheme matches the requested pattern.
#[cold]
fn no_grapheme_matching_pattern(pattern: CharClass) -> EcoString {
    eco_format!(
        "no grapheme matching pattern {} found in string",
        pattern.into_value().repr()
    )
}

